/**
 * Organizer Athlete Detail Page
 *
 * Single-registration editor: captain + teammate profile edits, team name,
 * division transfer, registration answers, waivers (read-only), and the
 * scores / video submissions surface.
 */
// @lat: [[organizer-dashboard#Registrations (Athletes)]]

import {
  createFileRoute,
  getRouteApi,
  Link,
  useNavigate,
  useRouter,
} from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { ArrowLeft, Shuffle, Trash2 } from "lucide-react"
import { useState } from "react"
import { toast } from "sonner"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { getCompetitionDivisionsWithCountsFn } from "@/server-fns/competition-divisions-fns"
import { getOrganizerAthleteDetailFn } from "@/server-fns/organizer-athlete-fns"
import { removeRegistrationFn } from "@/server-fns/registration-fns"
import { TransferDivisionDialog } from "../-components/transfer-division-dialog"
import { AnswersSection } from "./-components/answers-section"
import { AthleteProfileCard } from "./-components/athlete-profile-card"
import { RegistrationInfoCard } from "./-components/registration-info-card"
import { ScoresSection } from "./-components/scores-section"
import { TeamMembersSection } from "./-components/team-members-section"
import { VideoSubmissionsSection } from "./-components/video-submissions-section"
import { WaiversSection } from "./-components/waivers-section"

const parentRoute = getRouteApi("/compete/organizer/$competitionId")

export const Route = createFileRoute(
  "/compete/organizer/$competitionId/athletes/$registrationId",
)({
  staleTime: 10_000,
  component: AthleteDetailPage,
  loader: async ({ params, parentMatchPromise }) => {
    const parentMatch = await parentMatchPromise
    const { competition } = parentMatch.loaderData!
    const [detail, divisionsResult] = await Promise.all([
      getOrganizerAthleteDetailFn({
        data: {
          registrationId: params.registrationId,
          competitionId: params.competitionId,
        },
      }),
      getCompetitionDivisionsWithCountsFn({
        data: {
          competitionId: params.competitionId,
          teamId: competition.organizingTeamId,
        },
      }),
    ])
    return { detail, divisions: divisionsResult.divisions }
  },
})

function formatDate(date: Date | string | null | undefined) {
  if (!date) return "—"
  return new Date(date).toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  })
}

function formatDateTime(date: Date | string | null | undefined) {
  if (!date) return "—"
  return new Date(date).toLocaleString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  })
}

function AthleteDetailPage() {
  const { competition } = parentRoute.useLoaderData()
  const { detail, divisions } = Route.useLoaderData()
  const router = useRouter()
  const navigate = useNavigate()
  const removeRegistration = useServerFn(removeRegistrationFn)

  const [showTransferDialog, setShowTransferDialog] = useState(false)
  const [showRemoveDialog, setShowRemoveDialog] = useState(false)
  const [isRemoving, setIsRemoving] = useState(false)

  const isTeamDivision = (detail.division?.teamSize ?? 1) > 1
  const captainName = [detail.captain?.firstName, detail.captain?.lastName]
    .filter(Boolean)
    .join(" ")
    .trim()
  const displayTitle =
    (isTeamDivision && detail.registration.teamName) ||
    captainName ||
    detail.captain?.email ||
    "Registration"

  const isRemoved = detail.registration.status === "removed"

  const handleRemoveRegistration = async () => {
    setIsRemoving(true)
    try {
      await removeRegistration({
        data: {
          registrationId: detail.registration.id,
          competitionId: competition.id,
        },
      })
      toast.success("Registration removed")
      setShowRemoveDialog(false)
      navigate({
        to: "/compete/organizer/$competitionId/athletes",
        params: { competitionId: competition.id },
      })
    } catch (error) {
      toast.error(
        error instanceof Error
          ? error.message
          : "Failed to remove registration",
      )
    } finally {
      setIsRemoving(false)
    }
  }

  // Captain + teammate memberships (for rendering profile cards)
  const members: Array<{
    userId: string
    firstName: string | null
    lastName: string | null
    email: string
    avatar: string | null
    isCaptain: boolean
    isActive: boolean
    joinedAt: Date | null
  }> = []

  if (detail.captain) {
    members.push({
      userId: detail.captain.id,
      firstName: detail.captain.firstName,
      lastName: detail.captain.lastName,
      email: detail.captain.email,
      avatar: detail.captain.avatar,
      isCaptain: true,
      isActive: true,
      joinedAt: null,
    })
  }

  if (detail.athleteTeam?.memberships) {
    for (const m of detail.athleteTeam.memberships) {
      if (m.userId === detail.registration.userId) continue
      if (!m.user) continue
      members.push({
        userId: m.userId,
        firstName: m.user.firstName,
        lastName: m.user.lastName,
        email: m.user.email,
        avatar: m.user.avatar,
        isCaptain: false,
        isActive: m.isActive,
        joinedAt: m.joinedAt,
      })
    }
  }

  // Parse affiliates from metadata
  let metadata: Record<string, unknown> | null = null
  if (detail.registration.metadata) {
    if (typeof detail.registration.metadata === "string") {
      try {
        metadata = JSON.parse(detail.registration.metadata)
      } catch {
        // ignore
      }
    } else {
      metadata = detail.registration.metadata as Record<string, unknown>
    }
  }
  const metadataAffiliates = metadata?.affiliates as
    | Record<string, string | null>
    | undefined

  return (
    <>
      <div className="flex flex-col gap-8 pb-12">
        {/* Page header */}
        <div className="flex flex-col gap-4">
          <div>
            <Button variant="ghost" size="sm" asChild className="-ml-2">
              <Link
                to="/compete/organizer/$competitionId/athletes"
                params={{ competitionId: competition.id }}
                search={{ tab: "athletes" }}
              >
                <ArrowLeft className="h-4 w-4 mr-1.5" />
                Back to Athletes
              </Link>
            </Button>
          </div>

          <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
            <div className="min-w-0 flex-1 space-y-2">
              <h1 className="text-3xl font-semibold tracking-tight truncate">
                {displayTitle}
              </h1>
              <div className="flex flex-wrap items-center gap-2">
                {detail.division && (
                  <Badge variant="outline">{detail.division.label}</Badge>
                )}
                {isRemoved ? (
                  <Badge variant="destructive">Removed</Badge>
                ) : (
                  <Badge
                    variant="outline"
                    className="bg-green-50 text-green-700 border-green-300 dark:bg-green-950 dark:text-green-300 dark:border-green-800"
                  >
                    Active
                  </Badge>
                )}
                {isTeamDivision && captainName && (
                  <span className="text-sm text-muted-foreground">
                    Captain: {captainName}
                  </span>
                )}
              </div>
            </div>
            <div className="flex items-center gap-2 shrink-0">
              <Button
                variant="outline"
                onClick={() => setShowTransferDialog(true)}
                disabled={isRemoved}
              >
                <Shuffle className="h-4 w-4 mr-2" />
                Change Division
              </Button>
              <Button
                variant="outline"
                onClick={() => setShowRemoveDialog(true)}
                disabled={isRemoved}
                className="text-destructive hover:text-destructive border-destructive/30 hover:bg-destructive/10"
              >
                <Trash2 className="h-4 w-4 mr-2" />
                Remove Registration
              </Button>
            </div>
          </div>
        </div>

        {/* Registration Info */}
        <RegistrationInfoCard
          registration={detail.registration}
          division={detail.division}
          competitionId={competition.id}
          isTeamDivision={isTeamDivision}
          commercePurchase={detail.commercePurchase}
          formatDate={formatDate}
          onChangeDivisionClick={() => setShowTransferDialog(true)}
        />

        {/* Members profile cards */}
        <div className="flex flex-col gap-6">
          <div>
            <h2 className="text-xl font-semibold tracking-tight">
              {isTeamDivision ? "Captain & Athletes" : "Athlete Profile"}
            </h2>
            <p className="text-sm text-muted-foreground mt-1">
              Editing a name or email updates that user's account profile
              everywhere.
            </p>
          </div>
          <div className="grid gap-4 md:grid-cols-2">
            {members.map((m) => (
              <AthleteProfileCard
                key={m.userId}
                member={m}
                affiliateName={metadataAffiliates?.[m.userId] ?? null}
                registrationId={detail.registration.id}
                competitionId={competition.id}
              />
            ))}
          </div>
        </div>

        {/* Team Members Section */}
        {isTeamDivision && detail.athleteTeam && (
          <TeamMembersSection
            registrationId={detail.registration.id}
            competitionId={competition.id}
            captainUserId={detail.registration.userId}
            teamSize={detail.division?.teamSize ?? 1}
            members={members}
            pendingInvites={detail.pendingInvites}
            formatDate={formatDate}
          />
        )}

        {/* Answers Section */}
        {detail.questions.length > 0 && (
          <AnswersSection
            registrationId={detail.registration.id}
            competitionId={competition.id}
            questions={detail.questions}
            answers={detail.answers}
            members={members}
            isTeamDivision={isTeamDivision}
          />
        )}

        {/* Waivers Section */}
        {detail.waivers.length > 0 && (
          <WaiversSection
            waivers={detail.waivers}
            waiverSignatures={detail.waiverSignatures}
            members={members}
            formatDate={formatDate}
          />
        )}

        {/* Scores / Submissions */}
        {competition.competitionType === "online" ? (
          <VideoSubmissionsSection
            registrationId={detail.registration.id}
            competitionId={competition.id}
            events={detail.events}
            videoSubmissions={detail.videoSubmissions}
            scores={detail.scores}
            members={members}
            teamSize={detail.division?.teamSize ?? 1}
            captainUserId={detail.registration.userId}
            formatDateTime={formatDateTime}
          />
        ) : (
          <ScoresSection
            registrationId={detail.registration.id}
            competitionId={competition.id}
            organizingTeamId={competition.organizingTeamId}
            divisionId={detail.registration.divisionId}
            events={detail.events}
            scores={detail.scores}
            members={members}
          />
        )}
      </div>

      {/* Remove dialog */}
      <AlertDialog open={showRemoveDialog} onOpenChange={setShowRemoveDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remove Registration</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to remove the registration for{" "}
              <strong>{displayTitle}</strong>? This removes them from the
              competition, deletes their heat assignments and scores. You'll be
              redirected back to the athletes list.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isRemoving}>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleRemoveRegistration}
              disabled={isRemoving}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {isRemoving ? "Removing..." : "Remove Registration"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Transfer division dialog */}
      {showTransferDialog && (
        <TransferDivisionDialog
          open={showTransferDialog}
          onOpenChange={(open) => {
            setShowTransferDialog(open)
            if (!open) router.invalidate()
          }}
          registration={{
            id: detail.registration.id,
            athleteName: displayTitle,
            divisionId: detail.registration.divisionId,
            divisionLabel: detail.division?.label ?? null,
            teamSize: detail.division?.teamSize ?? 1,
          }}
          divisions={divisions}
          competitionId={competition.id}
          registeredDivisionIds={[]}
        />
      )}
    </>
  )
}

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { Check, Pencil, X } from "lucide-react"
import { useState } from "react"
import { toast } from "sonner"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { updateRegistrationAnswerFn } from "@/server-fns/organizer-athlete-fns"
import {
  type AthleteDetailMember,
  type AthleteDetailQuestion,
  memberDisplayName,
} from "./types"

function parseOptions(opts: string | null): string[] | null {
  if (!opts) return null
  try {
    const parsed = JSON.parse(opts)
    return Array.isArray(parsed) ? (parsed as string[]) : null
  } catch {
    return null
  }
}

interface AnswersSectionProps {
  registrationId: string
  competitionId: string
  questions: AthleteDetailQuestion[]
  answers: Record<string, string> // `${userId}:${questionId}` -> answer
  members: AthleteDetailMember[]
  isTeamDivision: boolean
}

export function AnswersSection({
  registrationId,
  competitionId,
  questions,
  answers,
  members,
  isTeamDivision,
}: AnswersSectionProps) {
  return (
    <Card>
      <CardHeader>
        <CardTitle>Registration Answers</CardTitle>
        <CardDescription>
          Answers supplied during registration. Edits save immediately —
          clearing a field deletes the answer.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {questions.map((question) => {
          const applicableMembers = question.forTeammates
            ? members.filter((m) => m.isActive)
            : members.filter((m) => m.isCaptain && m.isActive)
          const effectiveMembers =
            applicableMembers.length > 0 ? applicableMembers : members
          return (
            <div key={question.id} className="space-y-3">
              <div className="space-y-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <div className="font-medium">{question.label}</div>
                  <Badge variant="secondary" className="text-xs">
                    {question.type}
                  </Badge>
                  {question.required && (
                    <Badge variant="outline" className="text-xs">
                      Required
                    </Badge>
                  )}
                </div>
                {question.helpText && (
                  <p className="text-xs text-muted-foreground">
                    {question.helpText}
                  </p>
                )}
              </div>
              <div className="space-y-2 pl-2 border-l-2">
                {effectiveMembers.map((member) => (
                  <AnswerRow
                    key={`${question.id}-${member.userId}`}
                    registrationId={registrationId}
                    competitionId={competitionId}
                    question={question}
                    member={member}
                    showMemberLabel={
                      isTeamDivision && effectiveMembers.length > 1
                    }
                    currentAnswer={
                      answers[`${member.userId}:${question.id}`] ?? ""
                    }
                  />
                ))}
              </div>
            </div>
          )
        })}
      </CardContent>
    </Card>
  )
}

interface AnswerRowProps {
  registrationId: string
  competitionId: string
  question: AthleteDetailQuestion
  member: AthleteDetailMember
  showMemberLabel: boolean
  currentAnswer: string
}

function AnswerRow({
  registrationId,
  competitionId,
  question,
  member,
  showMemberLabel,
  currentAnswer,
}: AnswerRowProps) {
  const router = useRouter()
  const updateAnswer = useServerFn(updateRegistrationAnswerFn)
  const [editing, setEditing] = useState(false)
  const [value, setValue] = useState(currentAnswer)
  const [isSaving, setIsSaving] = useState(false)

  const handleSave = async () => {
    setIsSaving(true)
    try {
      await updateAnswer({
        data: {
          registrationId,
          competitionId,
          userId: member.userId,
          questionId: question.id,
          answer: value,
        },
      })
      toast.success("Answer saved")
      setEditing(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to save answer",
      )
    } finally {
      setIsSaving(false)
    }
  }

  const handleCancel = () => {
    setValue(currentAnswer)
    setEditing(false)
  }

  return (
    <div className="flex items-start gap-3 py-2">
      {showMemberLabel && (
        <div className="text-xs text-muted-foreground w-32 shrink-0 pt-2 truncate">
          {memberDisplayName(member)}
        </div>
      )}
      <div className="flex-1 min-w-0">
        {editing ? (
          <div className="flex items-start gap-2">
            {question.type === "select" && parseOptions(question.options) ? (
              <Select value={value} onValueChange={setValue}>
                <SelectTrigger className="max-w-md">
                  <SelectValue placeholder="Select an option" />
                </SelectTrigger>
                <SelectContent>
                  {(parseOptions(question.options) ?? []).map((opt) => (
                    <SelectItem key={opt} value={opt}>
                      {opt}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            ) : question.type === "number" ? (
              <Input
                type="number"
                value={value}
                onChange={(e) => setValue(e.target.value)}
                disabled={isSaving}
                className="max-w-md"
              />
            ) : value.length > 60 ? (
              <Textarea
                value={value}
                onChange={(e) => setValue(e.target.value)}
                disabled={isSaving}
                rows={3}
                className="max-w-md"
              />
            ) : (
              <Input
                value={value}
                onChange={(e) => setValue(e.target.value)}
                disabled={isSaving}
                className="max-w-md"
              />
            )}
            <Button
              size="icon"
              variant="outline"
              onClick={handleSave}
              disabled={isSaving}
              aria-label="Save answer"
              className="h-9 w-9 shrink-0"
            >
              <Check className="h-4 w-4" />
            </Button>
            <Button
              size="icon"
              variant="ghost"
              onClick={handleCancel}
              disabled={isSaving}
              aria-label="Cancel"
              className="h-9 w-9 shrink-0"
            >
              <X className="h-4 w-4" />
            </Button>
          </div>
        ) : (
          <button
            type="button"
            onClick={() => setEditing(true)}
            className="group flex items-start gap-2 text-left w-full rounded-md hover:bg-muted/50 -mx-2 px-2 py-1.5"
          >
            <span
              className={
                currentAnswer
                  ? "text-sm flex-1"
                  : "text-sm italic text-muted-foreground flex-1"
              }
            >
              {currentAnswer || "Not answered"}
            </span>
            <Pencil className="h-3.5 w-3.5 text-muted-foreground opacity-0 group-hover:opacity-100 mt-0.5 shrink-0" />
          </button>
        )}
      </div>
    </div>
  )
}

import { Link, useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { ExternalLink, Plus, Trash2 } from "lucide-react"
import { useState } from "react"
import { toast } from "sonner"
import { EnterScoreForm } from "@/components/compete/enter-score-form"
import { OrganizerVideoLinksEditor } from "@/components/compete/organizer-video-links-editor"
import { VideoPlayerEmbed } from "@/components/compete/video-player-embed"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { deleteOrganizerVideoSubmissionFn } from "@/server-fns/organizer-athlete-fns"
import type { EventDetails } from "@/server-fns/submission-verification-fns"
import { ManualSubmissionDialog } from "./manual-submission-dialog"
import {
  type AthleteDetailEvent,
  type AthleteDetailMember,
  type AthleteDetailScore,
  type AthleteDetailVideoSubmission,
  memberDisplayName,
} from "./types"

interface EventSubmissionCardProps {
  event: AthleteDetailEvent
  registrationId: string
  competitionId: string
  submissions: AthleteDetailVideoSubmission[]
  scores: AthleteDetailScore[]
  members: AthleteDetailMember[]
  teamSize: number
  captainUserId: string
  formatDateTime: (d: Date | string | null | undefined) => string
}

export function EventSubmissionCard({
  event,
  registrationId,
  competitionId,
  submissions,
  scores,
  members,
  teamSize,
  captainUserId,
  formatDateTime,
}: EventSubmissionCardProps) {
  const router = useRouter()
  const deleteSubmission = useServerFn(deleteOrganizerVideoSubmissionFn)

  const [deleteTarget, setDeleteTarget] =
    useState<AthleteDetailVideoSubmission | null>(null)
  const [isDeleting, setIsDeleting] = useState(false)
  const [showManualDialog, setShowManualDialog] = useState(false)
  const [editingVideoLinks, setEditingVideoLinks] = useState(false)
  const [enteringScoreForSubmission, setEnteringScoreForSubmission] = useState<
    string | null
  >(null)

  const captainScore = scores.find((s) => s.userId === captainUserId)
  const submissionByIndex = new Map<number, AthleteDetailVideoSubmission>()
  for (const s of submissions) submissionByIndex.set(s.videoIndex, s)

  const slots = Array.from({ length: Math.max(teamSize, 1) }, (_, i) => ({
    index: i,
    submission: submissionByIndex.get(i) ?? null,
  }))

  const hasAnySubmission = submissions.length > 0

  const eventDetails: EventDetails = {
    id: event.trackWorkoutId,
    trackOrder: event.ordinal,
    workout: {
      id: event.trackWorkoutId,
      name: event.workoutName,
      description: "",
      scheme: event.scheme,
      scoreType: event.scoreType,
      timeCap: event.timeCap,
      roundsToScore: 1,
      repsPerRound: null,
      tiebreakScheme: event.tiebreakScheme,
    },
    submissionWindow: {
      opensAt: event.submissionWindowStartsAt
        ? new Date(event.submissionWindowStartsAt).toISOString()
        : null,
      closesAt: event.submissionWindowEndsAt
        ? new Date(event.submissionWindowEndsAt).toISOString()
        : null,
    },
  }

  const handleDelete = async () => {
    if (!deleteTarget) return
    setIsDeleting(true)
    try {
      await deleteSubmission({
        data: { submissionId: deleteTarget.id, competitionId },
      })
      toast.success("Submission deleted")
      setDeleteTarget(null)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to delete submission",
      )
    } finally {
      setIsDeleting(false)
    }
  }

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between gap-3 flex-wrap">
            <div className="min-w-0 space-y-1">
              <div className="flex items-center gap-2 flex-wrap">
                <CardTitle className="truncate">{event.workoutName}</CardTitle>
                <Badge variant="outline" className="text-xs">
                  {event.scheme}
                </Badge>
              </div>
              <CardDescription className="text-xs">
                Window: {formatDateTime(event.submissionWindowStartsAt)} →{" "}
                {formatDateTime(event.submissionWindowEndsAt)}
              </CardDescription>
            </div>
            {hasAnySubmission && (
              <Button
                variant="outline"
                size="sm"
                onClick={() => setEditingVideoLinks((v) => !v)}
                className="shrink-0"
              >
                {editingVideoLinks ? "Close video editor" : "Edit video URLs"}
              </Button>
            )}
          </div>
        </CardHeader>

        <CardContent className="space-y-5">
          {editingVideoLinks && (
            <OrganizerVideoLinksEditor
              submissions={submissions.map((s) => ({
                id: s.id,
                videoIndex: s.videoIndex,
                videoUrl: s.videoUrl,
              }))}
              competitionId={competitionId}
              teamSize={teamSize}
              registrationId={registrationId}
              trackWorkoutId={event.trackWorkoutId}
            />
          )}

          {captainScore && (
            <div className="flex items-center justify-between gap-3 rounded-md bg-muted/40 px-3 py-2 text-sm">
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-xs uppercase tracking-wide text-muted-foreground">
                  Score
                </span>
                <span className="font-mono font-medium">
                  {captainScore.scoreValue ?? "—"}
                </span>
                <Badge variant="outline" className="text-xs">
                  {captainScore.scoreStatus}
                </Badge>
              </div>
              {submissions[0] && (
                <Button variant="ghost" size="sm" asChild className="shrink-0">
                  <Link
                    to="/compete/organizer/$competitionId/events/$eventId/submissions/$submissionId"
                    params={{
                      competitionId,
                      eventId: event.trackWorkoutId,
                      submissionId: submissions[0].id,
                    }}
                  >
                    Review & adjust
                    <ExternalLink className="h-3 w-3 ml-1" />
                  </Link>
                </Button>
              )}
            </div>
          )}

          <div className="space-y-4">
            {slots.map(({ index, submission }) => {
              const slotLabel =
                teamSize <= 1
                  ? "Submission"
                  : index === 0
                    ? "Captain video"
                    : `Teammate video ${index}`
              const slotMember =
                submission &&
                members.find((m) => m.userId === submission.userId)

              if (!submission) {
                return (
                  <div
                    key={`empty-${index}`}
                    className="rounded-md border border-dashed p-4 flex items-center justify-between gap-3 flex-wrap"
                  >
                    <div className="min-w-0">
                      <div className="text-sm font-medium">{slotLabel}</div>
                      <div className="text-xs text-muted-foreground">
                        No submission yet.
                      </div>
                    </div>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setShowManualDialog(true)}
                    >
                      <Plus className="h-3.5 w-3.5 mr-1.5" />
                      Add manually
                    </Button>
                  </div>
                )
              }

              const hasScore = !!scores.find(
                (s) => s.userId === submission.userId,
              )

              return (
                <div key={submission.id} className="space-y-2">
                  <div className="flex items-center justify-between gap-2 flex-wrap">
                    <div className="flex items-center gap-2 flex-wrap">
                      <div className="text-sm font-medium">{slotLabel}</div>
                      {slotMember && (
                        <span className="text-xs text-muted-foreground">
                          {memberDisplayName(slotMember)}
                        </span>
                      )}
                      <Badge variant="secondary" className="text-xs">
                        {submission.status}
                      </Badge>
                    </div>
                    <div className="flex items-center gap-1.5">
                      {!hasScore && submission.videoIndex === 0 && (
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() =>
                            setEnteringScoreForSubmission(
                              enteringScoreForSubmission === submission.id
                                ? null
                                : submission.id,
                            )
                          }
                        >
                          {enteringScoreForSubmission === submission.id
                            ? "Close"
                            : "Enter score"}
                        </Button>
                      )}
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setDeleteTarget(submission)}
                        className="text-destructive hover:text-destructive hover:bg-destructive/10"
                      >
                        <Trash2 className="h-3.5 w-3.5 mr-1.5" />
                        Delete
                      </Button>
                    </div>
                  </div>
                  <div className="rounded-md overflow-hidden border bg-black">
                    <VideoPlayerEmbed url={submission.videoUrl} />
                  </div>
                  {submission.notes && (
                    <div className="text-xs text-muted-foreground">
                      Notes: {submission.notes}
                    </div>
                  )}
                  {enteringScoreForSubmission === submission.id && (
                    <EnterScoreForm
                      videoSubmissionId={submission.id}
                      competitionId={competitionId}
                      trackWorkoutId={event.trackWorkoutId}
                      event={eventDetails}
                    />
                  )}
                </div>
              )
            })}
          </div>
        </CardContent>
      </Card>

      <AlertDialog
        open={!!deleteTarget}
        onOpenChange={(open) => !open && setDeleteTarget(null)}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete video submission</AlertDialogTitle>
            <AlertDialogDescription>
              {deleteTarget?.videoIndex === 0
                ? "This also removes the linked score for this event."
                : "This removes the teammate's video slot. The captain's score is preserved."}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDelete}
              disabled={isDeleting}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {isDeleting ? "Deleting..." : "Delete"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <ManualSubmissionDialog
        open={showManualDialog}
        onOpenChange={setShowManualDialog}
        registrationId={registrationId}
        competitionId={competitionId}
        trackWorkoutId={event.trackWorkoutId}
        members={members}
        teamSize={teamSize}
        existingSubmissionIndexes={submissions.map((s) => s.videoIndex)}
      />
    </>
  )
}

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { Check, Pencil, X } from "lucide-react"
import { useState } from "react"
import { toast } from "sonner"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { updateRegistrationTeamNameFn } from "@/server-fns/organizer-athlete-fns"
import type {
  AthleteDetailCommercePurchase,
  AthleteDetailDivision,
  AthleteDetailRegistration,
} from "./types"

interface RegistrationInfoCardProps {
  registration: AthleteDetailRegistration
  division: AthleteDetailDivision | null
  competitionId: string
  isTeamDivision: boolean
  commercePurchase: AthleteDetailCommercePurchase | null
  formatDate: (d: Date | string | null | undefined) => string
  onChangeDivisionClick: () => void
}

export function RegistrationInfoCard({
  registration,
  division,
  competitionId,
  isTeamDivision,
  commercePurchase,
  formatDate,
  onChangeDivisionClick,
}: RegistrationInfoCardProps) {
  const router = useRouter()
  const updateTeamName = useServerFn(updateRegistrationTeamNameFn)

  const [editingTeamName, setEditingTeamName] = useState(false)
  const [teamNameInput, setTeamNameInput] = useState(
    registration.teamName ?? "",
  )
  const [isSavingTeamName, setIsSavingTeamName] = useState(false)

  const handleSaveTeamName = async () => {
    const trimmed = teamNameInput.trim()
    if (!trimmed) {
      toast.error("Team name cannot be empty")
      return
    }
    setIsSavingTeamName(true)
    try {
      await updateTeamName({
        data: {
          registrationId: registration.id,
          competitionId,
          teamName: trimmed,
        },
      })
      toast.success("Team name updated")
      setEditingTeamName(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to update team name",
      )
    } finally {
      setIsSavingTeamName(false)
    }
  }

  const paidAmount =
    commercePurchase?.totalCents != null
      ? `$${(commercePurchase.totalCents / 100).toFixed(2)}`
      : null

  return (
    <Card>
      <CardHeader>
        <CardTitle>Registration Details</CardTitle>
        <CardDescription>
          High-level information about this registration.
        </CardDescription>
      </CardHeader>
      <CardContent className="grid gap-6 sm:grid-cols-2">
        {isTeamDivision && (
          <div className="space-y-1.5 sm:col-span-2">
            <div className="text-xs uppercase tracking-wide text-muted-foreground">
              Team Name
            </div>
            {editingTeamName ? (
              <div className="flex items-center gap-2">
                <Input
                  value={teamNameInput}
                  onChange={(e) => setTeamNameInput(e.target.value)}
                  disabled={isSavingTeamName}
                  autoFocus
                  className="max-w-sm"
                />
                <Button
                  size="icon"
                  variant="outline"
                  onClick={handleSaveTeamName}
                  disabled={isSavingTeamName}
                  aria-label="Save team name"
                >
                  <Check className="h-4 w-4" />
                </Button>
                <Button
                  size="icon"
                  variant="ghost"
                  onClick={() => {
                    setEditingTeamName(false)
                    setTeamNameInput(registration.teamName ?? "")
                  }}
                  disabled={isSavingTeamName}
                  aria-label="Cancel team name edit"
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>
            ) : (
              <div className="flex items-center gap-2">
                <span className="text-base font-medium">
                  {registration.teamName || (
                    <span className="text-muted-foreground italic font-normal">
                      Unnamed Team
                    </span>
                  )}
                </span>
                <Button
                  size="icon"
                  variant="ghost"
                  onClick={() => setEditingTeamName(true)}
                  aria-label="Edit team name"
                  className="h-7 w-7"
                >
                  <Pencil className="h-3.5 w-3.5" />
                </Button>
              </div>
            )}
          </div>
        )}

        <div className="space-y-1.5">
          <div className="text-xs uppercase tracking-wide text-muted-foreground">
            Division
          </div>
          <div className="flex items-center gap-2">
            {division ? (
              <Badge variant="outline" className="text-sm">
                {division.label}
              </Badge>
            ) : (
              <span className="text-muted-foreground">—</span>
            )}
            <Button
              size="sm"
              variant="ghost"
              onClick={onChangeDivisionClick}
              className="h-7 px-2 text-xs"
            >
              Change
            </Button>
          </div>
        </div>

        <div className="space-y-1.5">
          <div className="text-xs uppercase tracking-wide text-muted-foreground">
            Registered
          </div>
          <div className="text-sm">{formatDate(registration.registeredAt)}</div>
        </div>

        <div className="space-y-1.5">
          <div className="text-xs uppercase tracking-wide text-muted-foreground">
            Payment Status
          </div>
          <div className="flex items-center gap-2 text-sm">
            {registration.paymentStatus ? (
              <Badge
                variant={
                  registration.paymentStatus === "paid"
                    ? "outline"
                    : "secondary"
                }
                className={
                  registration.paymentStatus === "paid"
                    ? "bg-green-50 text-green-700 border-green-300 dark:bg-green-950 dark:text-green-300 dark:border-green-800"
                    : ""
                }
              >
                {registration.paymentStatus}
              </Badge>
            ) : (
              <span className="text-muted-foreground">—</span>
            )}
            {paidAmount && (
              <span className="text-muted-foreground">{paidAmount}</span>
            )}
          </div>
        </div>

        <div className="space-y-1.5">
          <div className="text-xs uppercase tracking-wide text-muted-foreground">
            Registration Status
          </div>
          <Badge
            variant={
              registration.status === "removed" ? "destructive" : "outline"
            }
            className={
              registration.status === "active"
                ? "bg-green-50 text-green-700 border-green-300 dark:bg-green-950 dark:text-green-300 dark:border-green-800"
                : ""
            }
          >
            {registration.status}
          </Badge>
        </div>
      </CardContent>
    </Card>
  )
}

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { useState } from "react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { createOrganizerVideoSubmissionFn } from "@/server-fns/organizer-athlete-fns"
import { type AthleteDetailMember, memberDisplayName } from "./types"

interface ManualSubmissionDialogProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  registrationId: string
  competitionId: string
  trackWorkoutId: string
  members: AthleteDetailMember[]
  teamSize: number
  existingSubmissionIndexes: number[]
}

export function ManualSubmissionDialog({
  open,
  onOpenChange,
  registrationId,
  competitionId,
  trackWorkoutId,
  members,
  teamSize,
  existingSubmissionIndexes,
}: ManualSubmissionDialogProps) {
  const router = useRouter()
  const create = useServerFn(createOrganizerVideoSubmissionFn)

  const activeMembers = members.filter((m) => m.isActive)
  const captain = activeMembers.find((m) => m.isCaptain) ?? activeMembers[0]
  const nextIndex = (() => {
    for (let i = 0; i < Math.max(teamSize, 1); i++) {
      if (!existingSubmissionIndexes.includes(i)) return i
    }
    return existingSubmissionIndexes.length
  })()

  const [userId, setUserId] = useState<string>(captain?.userId ?? "")
  const [videoUrl, setVideoUrl] = useState("")
  const [score, setScore] = useState("")
  const [notes, setNotes] = useState("")
  const [isSaving, setIsSaving] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const reset = () => {
    setUserId(captain?.userId ?? "")
    setVideoUrl("")
    setScore("")
    setNotes("")
    setError(null)
  }

  const handleSubmit = async () => {
    setError(null)
    if (!userId) {
      setError("Select which member this submission is for")
      return
    }
    if (!videoUrl.trim()) {
      setError("Video URL is required")
      return
    }
    try {
      // basic URL sanity check
      new URL(videoUrl.trim())
    } catch {
      setError("Enter a valid video URL (including https://)")
      return
    }
    setIsSaving(true)
    try {
      await create({
        data: {
          registrationId,
          competitionId,
          trackWorkoutId,
          userId,
          videoUrl: videoUrl.trim(),
          videoIndex: nextIndex,
          notes: notes.trim() || undefined,
          score: score.trim() || undefined,
          scoreStatus: score.trim() ? "scored" : undefined,
        },
      })
      toast.success("Submission added")
      reset()
      onOpenChange(false)
      router.invalidate()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to add submission")
    } finally {
      setIsSaving(false)
    }
  }

  return (
    <Dialog
      open={open}
      onOpenChange={(next) => {
        if (!next) reset()
        onOpenChange(next)
      }}
    >
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Add submission manually</DialogTitle>
          <DialogDescription>
            Create a video submission on the athlete's behalf. Video slot{" "}
            {nextIndex + 1} of {teamSize}. Scoring only applies to the captain
            slot (video 1).
          </DialogDescription>
        </DialogHeader>
        <div className="space-y-4 py-1">
          {teamSize > 1 && (
            <div className="space-y-1.5">
              <Label htmlFor="manual-member">Member</Label>
              <Select value={userId} onValueChange={setUserId}>
                <SelectTrigger id="manual-member">
                  <SelectValue placeholder="Select member" />
                </SelectTrigger>
                <SelectContent>
                  {activeMembers.map((m) => (
                    <SelectItem key={m.userId} value={m.userId}>
                      {memberDisplayName(m)}
                      {m.isCaptain && " (Captain)"}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}
          <div className="space-y-1.5">
            <Label htmlFor="manual-url">Video URL</Label>
            <Input
              id="manual-url"
              value={videoUrl}
              onChange={(e) => setVideoUrl(e.target.value)}
              placeholder="https://youtube.com/..."
              disabled={isSaving}
            />
          </div>
          {nextIndex === 0 && (
            <div className="space-y-1.5">
              <Label htmlFor="manual-score">Score (optional)</Label>
              <Input
                id="manual-score"
                value={score}
                onChange={(e) => setScore(e.target.value)}
                placeholder="e.g. 4:32 or 180 reps"
                disabled={isSaving}
                className="font-mono"
              />
              <p className="text-xs text-muted-foreground">
                Leave blank to enter the score later from the event card.
              </p>
            </div>
          )}
          <div className="space-y-1.5">
            <Label htmlFor="manual-notes">Notes (optional)</Label>
            <Textarea
              id="manual-notes"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              disabled={isSaving}
              rows={2}
            />
          </div>
          {error && (
            <p className="text-sm text-destructive" role="alert">
              {error}
            </p>
          )}
        </div>
        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isSaving}
          >
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={isSaving}>
            {isSaving ? "Saving..." : "Create submission"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

